 * has 26 elements (one per letter).  The implementation uses
 * OpenMP thread‑local buffers to avoid false sharing and then
 * combines them in a single pass at the end.
 */
void firstLetterCounts(std::vector<std::string> const& s,
                       std::array<std::size_t, 26>& bins)
{
    // Thread‑private scratch space
    const int num_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 26>> local_bins(num_threads);

    // Zero all thread buffers
    for (auto& a : local_bins) a.fill(0);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto& thread_buf = local_bins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < s.size(); ++i) {
            // guard against an empty string
            const std::string& str = s[i];
            if (str.empty()) continue;

            // use C‑style string access to avoid bounds checks
            const char c = str.front();
            const int idx = c - 'a';
            if (idx >= 0 && idx < 26)
                ++thread_buf[idx];
        }
    }

    // Merge local buffers into the final result
    bins.fill(0);
    for (const auto& a : local_bins) {
        for (int j = 0; j < 26; ++j)
            bins[j] += a[j];
    }
