#pragma once
#include <vector>
#include <limits>
#include <cstring>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A. A is an NxN matrix stored in row-major order,
   the graph is connected and undirected. */
inline int shortestPathLength(std::vector<int> const& A,
                              size_t N,
                              int source,
                              int dest) noexcept
{
    if (source == dest) return 0;

    // Visited array – a byte per vertex is enough.
    std::vector<char> visited(N, 0);
    visited[source] = 1;

    // Simple circular queue: two contiguous buffers, one for vertices, one for depths.
    std::vector<int> qv(N);
    std::vector<int> qd(N);
    size_t head = 0, tail = 0;

    qv[tail] = source;
    qd[tail] = 0;
    ++tail;

    while (head != tail) {
        int cur = qv[head];
        int dist = qd[head];
        ++head;
        if (head == N) head = 0;          // wrap around

        // Scan all neighbors of cur
        const int off = static_cast<int>(cur) * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[off + i] && !visited[i]) {
                visited[i] = 1;
                qv[tail] = i;
                qd[tail] = dist + 1;
                ++tail;
                if (tail == N) tail = 0;  // wrap around
                if (i == dest) return dist + 1;
            }
        }
    }

    // Should not happen – graph guaranteed connected
    return std::numeric_limits<int>::max();
}
