#pragma once
#include <vector>

struct Element {
    size_t index;
    double value;
};

/**
 * Compute z = alpha*x+y where x and y are sparse vectors.
 * z must be a dense array of size large enough to hold the highest index in x or y.
 */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double>& z)
{
    // Sequential merge of the two sorted index lists – exactly preserves
    // the original behaviour while keeping the implementation simple
    // and safe for large indices.
    size_t xi = 0, yi = 0;
    const size_t xs = x.size(), ys = y.size();

    while (xi < xs && yi < ys) {
        size_t ix = x[xi].index;
        size_t iy = y[yi].index;
        if (ix < iy) {
            z[ix] += alpha * x[xi].value;
            ++xi;
        } else if (ix > iy) {
            z[iy] += y[yi].value;
            ++yi;
        } else {           // ix == iy
            z[ix] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }

    // Remaining entries of x
    while (xi < xs) {
        z[x[xi].index] += alpha * x[xi].value;
        ++xi;
    }

    // Remaining entries of y
    while (yi < ys) {
        z[y[yi].index] += y[yi].value;
        ++yi;
    }
}
