struct COOElement {
    std::size_t row, column;
    double value;
};

/*
 * Compute y = alpha*A*x + beta*y where alpha and beta are scalars,
 * x and y are vectors, and A is a sparse matrix stored in COO format.
 * x and y are length N and A is M x N.
 *
 * The implementation is fully parallelised using OpenMP.  To avoid
 * race conditions when multiple threads add to the same entry of y,
 * each update is performed with an atomic add.  This preserves the
 * exact results of the sequential reference code while giving
 * substantial speed‑ups on systems with multiple cores.
 */
inline void spmv(double alpha, const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta, std::vector<double> &y,
                 std::size_t M, std::size_t N)
{
    /* Scale the result vector by beta */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    /* Accumulate contributions from the sparse matrix */
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < A.size(); ++idx) {
        const auto &elem = A[idx];
        if (elem.row < M && elem.column < N) {
            double prod = alpha * elem.value * x[elem.column];
            /* atomic add guarantees thread‑safe accumulation with exact ordering */
            #pragma omp atomic
            y[elem.row] += prod;
        }
    }
}
