#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// In-place DFT – keep the original API but greatly accelerate it
void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output) {
    const std::size_t N = x.size();
    output.resize(N);

    // Angular constant
    const double twopi = 2.0 * M_PI;
    const double invN  = 1.0 / static_cast<double>(N);

    // Parallel over output index `k`, store results directly into output
    #pragma omp parallel for schedule(static)
    for (std::intptr_t k = 0; k < static_cast<std::intptr_t>(N); ++k) {
        // Precompute the twiddle generator: w = exp(-i * 2πk/N)
        const double theta = twopi * static_cast<double>(k) * invN;
        const double cosTheta = std::cos(theta);
        const double sinTheta = std::sin(theta);          // sin is negative in exp(-iθ)

        std::complex<double> c(cosTheta, -sinTheta);      // exp(-iθ) = cosθ - i sinθ
        std::complex<double> w = c;                       // current twiddle factor

        std::complex<double> sum(0.0, 0.0);
        for (std::size_t n = 0; n < N; ++n) {
            sum += std::complex<double>(x[n], 0.0) * w;
            // Update w by multiplying with the base twiddle factor once per n
            w *= c;
        }
        output[k] = sum;
    }
}
