int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    const std::size_t n = x.size();
    if (n == 0) return 0;

    std::vector<int64_t> prefix(n);
    std::vector<int64_t> block_sum(omp_get_max_threads() + 1, 0);

    // 1. Compute partial prefixes and block sums in parallel
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t sz = omp_get_num_threads();
        std::size_t chunk = (n + sz - 1) / sz;          // ceil division
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);

        if (start < end) {
            // local prefix scan
            int64_t running = x[start];
            prefix[start] = running;
            for (std::size_t i = start + 1; i < end; ++i) {
                running += x[i];
                prefix[i] = running;
            }
            block_sum[tid + 1] = running; // last value of this block
        }
    }

    // 2. Prefix scan over block sums to compute offsets
    for (std::size_t i = 1; i < block_sum.size(); ++i)
        block_sum[i] += block_sum[i - 1];

    // 3. Add offsets to each block's prefix values
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t sz = omp_get_num_threads();
        std::size_t chunk = (n + sz - 1) / sz;
        std::size_t start = tid * chunk;
        std::size_t end   = std::min(start + chunk, n);
        int64_t offset = block_sum[tid]; // sum of all previous blocks

        for (std::size_t i = start; i < end; ++i)
            prefix[i] += offset;
    }

    // 4. Final accumulation of prefix sums
    int64_t total = 0;
    #pragma omp parallel for reduction(+:total)
