/* Union‑Find data structure */
struct UF {
    std::vector<int> parent;
    std::vector<int> rank;
    UF(int n) : parent(n), rank(n, 0) {
        std::iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    void unite(int a, int b) {
        int ra = find(a), rb = find(b);
        if (ra == rb) return;
        if (rank[ra] < rank[rb]) parent[ra] = rb;
        else if (rank[ra] > rank[rb]) parent[rb] = ra;
        else { parent[rb] = ra; ++rank[ra]; }
    }
};

/* Return the number of vertices in the largest component of the graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major. */
int largestComponent(std::vector<int> const& A, size_t N) {
    if (N == 0) return 0;
    UF uf(static_cast<int>(N));

    /* Parallel union of edges */
#pragma omp parallel for schedule(dynamic)
    for (long long i = 0; i < static_cast<long long>(N); ++i) {
        const long long row = i * N;
        for (int j = i + 1; j < static_cast<int>(N); ++j) {
            if (A[row + j] == 1) uf.unite(static_cast<int>(i), j);
        }
    }

    /* Count component sizes */
    std::vector<int> compSize(N, 0);
    int maxSize = 0;
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int root = uf.find(i);
#pragma omp atomic
        compSize[root]++;
    }

    /* Find maximum component size */
    for (int sz : compSize) if (sz > maxSize) maxSize = sz;
    return maxSize;
}
