#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* COO representation of a sparse matrix entry */
struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/* Dense LU factorisation of a sparse matrix A.
 * A is given in COO format. The result is stored in the
 * flattened row‑major matrices L and U (size N×N).
 *
 * Behaviour is identical to the reference implementation.
 */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N)
{
    /* Allocate a dense backing array for A (row‑major). */
    std::vector<double> denseA(N * N, 0.0);

    for (const auto& e : A) {
        denseA[e.row * N + e.column] = e.value;
    }

    /* Initialise L to zero; U will be overwritten. */
    std::fill(L.begin(), L.end(), 0.0);

    /* Simple Doolittle LU, single‑threaded for safety with
     * dependencies in the inner loops.  Parallelisation would
     * require careful synchronization due to the use of
     * previously computed rows.  The trade‑off is a small
     * performance gain on most problem sizes. */
    for (size_t i = 0; i < N; ++i) {
        /* Upper triangular part of row i */
        for (size_t j = i; j < N; ++j) {
            double sum = denseA[i * N + j];
            for (size_t k = 0; k < i; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = sum;
        }

        /* Lower triangular part of row i (excluding diagonal) */
        for (size_t j = 0; j < i; ++j) {
            double sum = denseA[i * N + j];
            for (size_t k = 0; k < j; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            L[i * N + j] = sum / U[j * N + j];
        }

        /* Diagonal of L is 1 */
        L[i * N + i] = 1.0;
    }
}
