/* Return the distance between the closest two elements in the vector x.
   Example:
     input: [7, 3, 9, 12, 31, 1]
     output: 2
*/
inline double closestPair(std::vector<double> const& x)
{
    const std::size_t N = x.size();
    if (N < 2)
        return 0.0;

    // Copy the data so that we can sort it
    std::vector<double> arr(x);

    // Sort once (STL sort is usually fast enough and thread‑safe)
    std::sort(arr.begin(), arr.end());

    // Scan the sorted array linearly – the closest pair is among neighbours
    double minDist = std::numeric_limits<double>::max();

    // Parallelize the linear scan with a reduction on minDist
    #pragma omp parallel for reduction(min:minDist)
    for (std::size_t i = 0; i + 1 < N; ++i)
    {
        const double d = std::abs(arr[i + 1] - arr[i]);
        if (d < minDist)
            minDist = d;
    }

    return minDist;
}
