/* 
   Set every cell's value to 1 if it has exactly one neighbor that's a 1. 
   Otherwise set it to 0.
   Only neighbors are considered, not the cell itself.  
   input and output are NxN grids of ints in row-major order.
*/
inline void cellsXOR(std::vector<int> const& input, std::vector<int>& output, size_t N)
{
    const size_t stride = N;
    /* Parallelize the two-dimensional iteration.  collapsing the loops gives
       a very balanced work distribution, even for small N. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            int count = 0;
            size_t base = i * stride + j;

            // neighbours
            if (i > 0             && input[(i-1)*stride + j] == 1) ++count;
            if (i < N-1           && input[(i+1)*stride + j] == 1) ++count;
            if (j > 0             && input[base - 1]           == 1) ++count;
            if (j < N-1           && input[base + 1]           == 1) ++count;

            output[base] = (count == 1) ? 1 : 0;
        }
    }
}
