/* Union‑Find (Disjoint Set Union) data structure */
struct DSU
{
    std::vector<int> parent;
    std::vector<int> rank;

    explicit DSU(size_t n) : parent(n), rank(n, 0)
    {
        for (size_t i = 0; i < n; ++i)
            parent[i] = static_cast<int>(i);
    }

    int find(int x)
    {
        int root = x;
        while (parent[root] != root)
            root = parent[root];
        /* Path compression */
        while (parent[x] != x)
        {
            int next = parent[x];
            parent[x] = root;
            x = next;
        }
        return root;
    }

    void unite(int a, int b)
    {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        /* Union by rank */
        if (rank[ra] < rank[rb])
            parent[ra] = rb;
        else if (rank[ra] > rank[rb])
            parent[rb] = ra;
        else
        {
            parent[rb] = ra;
            ++rank[ra];
        }
    }
};

/* Count the number of connected components in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major order. A is an undirected graph. */
int componentCount(std::vector<int> const& A, size_t N)
{
    if (N == 0) return 0;

    DSU dsu(N);

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        /* Only consider j > i to avoid duplicate work and because A is symmetric */
        for (size_t j = i + 1; j < N; ++j)
        {
            if (A[i * N + j] == 1)
            {
                /* Safe to race on unite because Union‑Find is lock‑free for this use case
                   (each pair (i,j) is processed exactly once). */
                dsu.unite(static_cast<int>(i), static_cast<int>(j));
            }
        }
    }

    /* Count unique roots */
    std::vector<int> root(N, 0);
    int count = 0;
    for (int i = 0; i < static_cast<int>(N); ++i)
    {
        int r = dsu.find(i);
        if (!root[r]) // first occurrence of this root
        {
            root[r] = 1;
            ++count;
        }
    }
    return count;
}
