#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of vector `x` into `output`.
 * The function is parallelised using OpenMP. It preserves the exact
 * behaviour of the original serial implementation.
 *
 * Example:
 *    input:  [1, 7, 4, 6, 6, 2]
 *    output: [1, 8,12,18,24,26]
 *
 * The algorithm works in three phases:
 *   1. Each thread computes a local prefix sum over its chunk
 *      and records the total sum of that chunk.
 *   2. A serial prefix sum is performed over the chunk totals.
 *   3. Each thread adds the accumulated total of all preceding chunks
 *      to its local prefix results.
 *
 * This approach is O(n) and scales well up to the number of hardware
 * threads available.
 */
inline void prefixSum(const std::vector<int64_t> &x,
                      std::vector<int64_t> &output)
{
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    const int num_threads = omp_get_max_threads();

    /* Store the total of each chunk. */
    std::vector<int64_t> chunk_totals(num_threads, 0);

    /* Phase 1: local prefix sums and chunk totals. */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t chunk_size = (n + num_threads - 1) / num_threads;
        const std::size_t start = tid * chunk_size;
        const std::size_t end   = std::min(n, (tid + 1) * chunk_size);

        if (start >= end) return;           // empty chunk

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        chunk_totals[tid] = sum;
    }

    /* Phase 2: serial prefix over chunk totals. */
    for (int i = 1; i < num_threads; ++i) {
        chunk_totals[i] += chunk_totals[i - 1];
    }

    /* Phase 3: add preceding chunk totals to each element. */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t chunk_size = (n + num_threads - 1) / num_threads;
        const std::size_t start = tid * chunk_size;
        const std::size_t end   = std::min(n, (tid + 1) * chunk_size);

        if (start == 0) return;      // first chunk needs no adjustment

        const int64_t add = chunk_totals[tid - 1];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += add;
        }
    }
}
