/*
   Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.  
   Each element of `input` will be averaged with its two neighbors and
   stored in the corresponding element of `output`.  Input indices that
   fall outside of the valid range contribute a zero value (the
   “ghost” value).  The function is thread‑safe and is parallelised
   with OpenMP to exploit the available cores.

   The implementation uses raw pointer arithmetic for minimal
   overhead, explicit handling of the two boundary elements, and a
   static schedule to minimise scheduling overhead.  The algorithm
   guarantees identical results to the original reference for any
   valid input vector.
*/
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output) {
    const std::size_t n = input.size();
    if (n == 0) return;

    const double* in  = input.data();
    double*        out = output.data();

    // Handle the first element (i == 0)
    out[0] = (in[0] + in[1]) / 3.0;

    // Handle the interior elements in parallel
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        const double sum = in[i - 1] + in[i] + in[i + 1];
        out[i] = sum / 3.0;
    }

    // Handle the last element (i == n-1)
    out[n - 1] = (in[n - 2] + in[n - 1]) / 3.0;
}
