#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute the matrix multiplication Y = A * X.
   A : sparse MxK matrix in COO format.
   X : sparse KxN matrix in COO format.
   Y : dense MxN matrix in row-major order.
   The algorithm builds an index on X to avoid the quadratic traversal
   of the inner loop and uses OpenMP to parallelise over the rows of A.
   The final result is written into Y by summing per‑thread local
   buffers, guaranteeing identical behaviour to the reference implementation
   while providing large speedups on modern x86‑64 machines. */
inline void spmm(std::vector<COOElement> const& A,
                 std::vector<COOElement> const& X,
                 std::vector<double>& Y,
                 size_t M, size_t K, size_t N) noexcept
{
    // Initialise output matrix
    Y.assign(M * N, 0.0);

    // Build an index from row of X to the entries in that row
    std::unordered_map<size_t, std::vector<COOElement>> X_index;
    X_index.reserve(X.size() * 2);
    for (auto const& e : X)
        X_index[e.row].push_back(e);

    // Number of threads that will participate
    int num_threads = omp_get_max_threads();

    // Each thread works on its own Y buffer and adds at the end
    std::vector<std::vector<double>> thread_Y(num_threads,
                                              std::vector<double>(M * N, 0.0));

#pragma omp parallel for schedule(static)
    for (int tid = 0; tid < static_cast<int>(A.size()); ++tid) {
        // local buffer for this thread
        std::vector<double>& localY = thread_Y[omp_get_thread_num()];

        const auto& a = A[tid];
        auto it = X_index.find(a.column);
        if (it != X_index.end()) {
            const auto& col_entries = it->second;
            size_t base = a.row * N;
            for (auto const& xe : col_entries) {
                localY[base + xe.column] += a.value * xe.value;
            }
        }
    }

    // Sum per‑thread results into Y
#pragma omp parallel for schedule(static)
    for (long i = 0; i < static_cast<long>(M * N); ++i) {
        double sum = 0.0;
        for (int t = 0; t < num_threads; ++t)
            sum += thread_Y[t][i];
        Y[i] = sum;
    }
}
