/// Computes z = alpha * x + y for two std::vector<double> objects.
/// The operation is performed in parallel using OpenMP.
/// The function assumes that *z* has already been sized to match *x* and *y*.
inline void axpy(double alpha,
                 std::vector<double> const& x,
                 std::vector<double> const& y,
                 std::vector<double> &z)
{
    const std::size_t n = x.size();

    // Ensure that the input vectors are of equal size.
    // If size mismatch occurs, the behaviour is undefined and the
    // function will simply write up to the smallest size.
    const std::size_t m = y.size();
    const std::size_t sz = (n < m) ? n : m;
    if (z.size() < sz) z.resize(sz);

    // Parallel loop: schedule(static) works best for contiguous data.
    #pragma omp parallel for schedule(static) default(none) \
        shared(alpha, x, y, z, sz)
    for (std::size_t i = 0; i < sz; ++i) {
        z[i] = alpha * x[i] + y[i];
    }
}
