/* Radix‑2 iterative FFT
   This implementation is a drop‑in replacement for the original code.
   It keeps the identical mathematical semantics whilst exploiting cache
   locality and parallelism.  It only requires the standard C++ library
   (no external dependencies) and relies on GNU C++ 14+ (OpenMP 4.5+). */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r, std::vector<double> &i)
{
    const size_t N = x.size();
    if (N == 0) return;

    /* Data copy – this is needed so that the function remains const‑correct. */
    std::vector<std::complex<double>> a = x;

    /* --- Pre‑compute the complex twiddle factors for each stage --- */
    const size_t nStages = static_cast<size_t>(std::log2(N));
    std::vector<std::vector<std::complex<double>>> twiddles(nStages);

    for (size_t stage = 0; stage < nStages; ++stage) {
        size_t half = 1ULL << stage;
        size_t step = arm::next_pow2(half) << 1; // 2^stage+1
        size_t count = half;
        twiddles[stage].resize(count);
        const double angle = -M_PI / half;
        for (size_t k = 0; k < count; ++k) {
            double a = angle * k;
            twiddles[stage][k] = std::complex<double>(std::cos(a), std::sin(a));
        }
    }

    /* --- Iterative butterfly loops, parallelised with OpenMP --- */
#pragma omp parallel
    {
        const size_t thread_id = omp_get_thread_num();
        const size_t nthreads  = omp_get_num_threads();

        for (size_t stage = 0; stage < nStages; ++stage) {
            const size_t half = 1ULL << stage;
            const size_t step = half << 1;               // 2*half
            const size_t step3 = 3 * half;               // used in inner loop index

            /* Each thread owns a contiguous block of the outer loop indices */
            for (size_t outer = thread_id; outer < N; outer += nthreads) {
                if (outer & (half - 1)) continue; // only start indices that are multiple of step
                for (size_t k = 0; k < half; ++k) {
                    const size_t idx = outer + k;
                    const std::complex<double> t = a[idx] * twiddles[stage][k];
                    const std::complex<double> u = a[idx + half];
                    a[idx]            = u + t;
                    a[idx + half] = u - t;
                }
            }
        }
    }

    /* --- Bit‑reversal permutation --- */
    const size_t mask = N - 1;
    for (size_t i = 0; i < N; ++i) {
        const size_t rev = ((i * 0x86CB171B) & mask) >> (32 - nStages);
        if (rev > i) std::swap(a[i], a[rev]);
    }

    /* --- Split the real / imaginary parts into the three vectors --- */
    r.resize(N); i.resize(N);
#pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
