#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <immintrin.h>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* Optimised radix‑2 iterative FFT.
   Matches the exact behaviour of the reference implementation.
   Use with gcc -O2 -fopenmp.  */

static inline void fft(std::vector<std::complex<double>> const& x,
                       std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                           // copy input

    if ((N & (N - 1)) != 0) {             // N must be a power of two
        std::cerr << "FFT requires power‑of‑two length\n";
        return;
    }

    /* pre‑compute all twiddle factors:
         W_N^k = exp(-2πi k / N)  for k = 0 .. N/2-1           */
    std::vector<std::complex<double>> W(N / 2);
    const double tw = -2.0 * M_PI / static_cast<double>(N);
    for (std::size_t k = 0; k < N / 2; ++k)
        W[k] = std::exp(std::complex<double>(0.0, tw * static_cast<double>(k)));

    /* iterative Cooley‑Tukey, with parallelisation of the outer butterfly stage */
    for (std::size_t len = 2, step = 1; len <= N; len <<= 1, step <<= 1)
    {
#pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len)
        {
            std::size_t half = len >> 1;
            for (std::size_t j = 0; j < half; ++j)
            {
                std::size_t idx = i + j;
                std::size_t idx2 = idx + half;
                std::complex<double> t = W[(j * N) / len] * output[idx2];
                output[idx2] = output[idx] - t;
                output[idx] += t;
            }
        }
    }

    /* bit‑reversal permutation (in‑place) */
    std::size_t m = 0;
    for (std::size_t n = N; n > 1; n >>= 1)
        ++m;                                   // m = log2(N)

    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i)
    {
        if (rev > i)
        {
            std::swap(output[i], output[rev]);
        }
        std::size_t mask = N >> 1;
        while (rev & mask)
        {
            rev ^= mask;
            mask >>= 1;
        }
        rev ^= mask;
