#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <cstddef>
#include <omp.h>

struct COOElement {
    std::size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax = b.
   A is a sparse NxN matrix in COO format.  x and b are dense vectors with N elements.
   The solver uses a naïve Gaussian elimination with partial pivoting.
   It is identical in behaviour to the reference implementation, but it
   stores the matrix in a compact flat 1‑D array and parallelises the
   inner loops with OpenMP.
*/
inline void solveLinearSystem(std::vector<COOElement> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              std::size_t N)
{
    /* Allocate a flattened NxN matrix and initialise to zero */
    std::vector<double> matrix(N * N, 0.0);

    /* Fill matrix from COO representation */
    for (auto const& e : A)
        matrix[e.row * N + e.column] = e.value;

    /* Work copy of the RHS */
    std::vector<double> rhs(b);

    /* Gaussian elimination with partial pivoting */
    for (std::size_t i = 0; i < N; ++i)
    {
        /* 1. Pivot selection */
        std::size_t pivot_row = i;
        double max_val = std::abs(matrix[i * N + i]);
        for (std::size_t k = i + 1; k < N; ++k)
        {
            double val = std::abs(matrix[k * N + i]);
            if (val > max_val)
            {
                max_val = val;
                pivot_row = k;
            }
        }

        /* 2. Swap pivot row with current row if necessary */
        if (pivot_row != i)
        {
            std::size_t idx_i = i * N;
            std::size_t idx_p = pivot_row * N;
            for (std::size_t c = 0; c < N; ++c)
                std::swap(matrix[idx_i + c], matrix[idx_p + c]);

            std::swap(rhs[i], rhs[pivot_row]);
        }

        /* 3. Eliminate below */
        double pivot = matrix[i * N + i];
        /* Parallelise over columns – each thread works on a part
           of the row.  The loop over rows `k` is sequential because
           each k depends on the previous eliminations. */
        for (std::size_t k = i + 1; k < N; ++k)
        {
            double factor = -matrix[k * N + i] / pivot;
            std::size_t idx_k = k * N;
            std::size_t idx_i = i * N;
#pragma omp simd
            for (std::size_t j = i; j < N; ++j)
            {
                if (j == i)
                    matrix[idx_k + j] = 0.0;
                else
                    matrix[idx_k + j] += factor * matrix[idx_i + j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    /* Back substitution */
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double sum = rhs[i];
        for (std::size_t j = i + 1; j < N; ++j)
            sum -= matrix[i * N + j] * x[j];
        x[i] = sum / matrix[i * N + i];
    }
}
