/* Compute one iteration of the 5‑point Jacobi stencil.
   Parallelised with OpenMP, pointer arithmetic and SIMD friendly,
   keeping the exact semantics of the original implementation.
*/
inline void jacobi2D(std::vector<double> const& input, std::vector<double> &output, size_t N) {
    if (N == 0) return;                            // nothing to do

    double const inv5 = 1.0 / 5.0;

    /* For better cache behaviour we use raw pointers and
       avoid the expensive bounds checks inside the inner loop. */
    const double* restrict in  = input.data();
    double*      restrict out = output.data();

    /* Parallelise over rows.  A two‑dimensional collapse gives
       good load‑balance on 8 cores. */
#pragma omp parallel for schedule(static) collapse(2)
    for (size_t i = 0; i < N; ++i) {
        size_t row_off = i * N;
        size_t prev_row_off = (i > 0      ? (i-1) * N : 0);
        size_t next_row_off = (i + 1 < N ? (i+1) * N : 0);

        for (size_t j = 0; j < N; ++j) {
            double sum = in[row_off + j];

            if (i > 0      ) sum += in[prev_row_off + j];
            if (i + 1 < N  ) sum += in[next_row_off + j];
            if (j > 0      ) sum += in[row_off + j - 1];
            if (j + 1 < N  ) sum += in[row_off + j + 1];

            out[row_off + j] = sum * inv5;
        }
    }
}
