#pragma once
#include <vector>
#include <algorithm>

/* Convex Hull – monotone chain (O(n log n))
   Input is unchanged.
   Output `hull` contains the vertices of the hull in counter‑clockwise order,
   starting with the lexicographically smallest point.  */
struct Point
{
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const size_t n = points.size();
    if (n < 3)
    {
        hull = points;
        return;
    }

    // Sort the points lexicographically by x, then y
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b)
              {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // The hull will never need more than 2*n points
    std::vector<Point> tmp;
    tmp.reserve(2 * n);
    size_t k = 0;  // number of points in tmp

    // Build lower hull
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(tmp[k - 2], tmp[k - 1], sorted[i]) <= 0)
            --k;
        tmp[k++] = sorted[i];
    }

    // Build upper hull (skip the first and last points of the lower hull)
    for (size_t i = n - 1, t = k + 1; i > 0; --i)
    {
        while (k >= t && cross(tmp[k - 2], tmp[k - 1], sorted[i - 1]) <= 0)
            --k;
        tmp[k++] = sorted[i - 1];
    }

    // Remove the duplicate endpoint
    tmp.resize(k - 1);
    hull = std::move(tmp);
}
