/* Compute twice the signed area of triangle ABC.
   Positive if ABC is counter‑clockwise.  The absolute value
   is used when comparing areas.  This avoids an extra abs() call
   inside the inner loop. */
inline double signedTriArea2(const Point& a, const Point& b, const Point& c) noexcept
{
    return (a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
}

double smallestArea(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

#ifdef _OPENMP
    /* Parallelise the outer loops.  A 3‑way nested loop is collapsed
       into a single two‑way loop so that the iterations are balanced. */
    #pragma omp parallel for schedule(static)
#endif
    for (std::size_t i = 0; i + 2 < n; ++i) {
        double localMin = minArea;                  // thread local copy
        for (std::size_t j = i + 1; j + 1 < n; ++j) {
            const double ab = (points[i].x * (points[j].y - points[j+1].y) +
                               points[j].x * (points[j+1].y - points[i].y) +
                               points[j+1].x * (points[i].y - points[j].y));
            // early bound: if the area with j and j+1 is already larger than current min,
            // the remaining k will also be larger because all areas are non‑negative.
            for (std::size_t k = j + 1; k < n; ++k) {
                const double area2 = std::abs(signedTriArea2(points[i], points[j], points[k]));
                double area = 0.5 * area2;
                if (area < localMin) localMin = area;
            }
        }
#ifndef _OPENMP
        // for serial execution: update global minimum
        if (localMin < minArea) minArea = localMin;
#else
        // Reduce thread local minima to global minimum
        #pragma omp critical
        if (localMin < minArea) minArea = localMin;
#endif
    }

    return minArea;
}
