// ---------- fast utilities --------------------------------------------------
inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}
inline double dist(const Point& a, const Point& b) noexcept
{
    return std::hypot(b.x - a.x, b.y - a.y);
}
// ------------------------------------------------------------------------------

// ---------- convex hull perimeter --------------------------------------------
inline double convexHullPerimeter(std::vector<Point> const& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // ----- sort points -------------------------------------------------------
    std::vector<Point> p(points);
    std::sort(p.begin(), p.end(), [](const Point& a, const Point& b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });

    // ----- build hull ---------------------------------------------------------
    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    // lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], p[i]) <= 0.0) k--;
        hull[k++] = p[i];
    }

    // upper hull
    for (std::size_t i = n - 1, t = k + 1; i-- > 0; )
    {
        while (k >= t && cross(hull[k - 2], hull[k - 1], p[i]) <= 0.0) k--;
        hull[k++] = p[i];
    }

    hull.resize(k - 1);          // last point repeats first one

    // ----- perimeter ---------------------------------------------------------
    double perim = 0.0;
    const std::size_t m = hull.size();
    for (std::size_t i = 0; i < m; ++i)
        perim += dist(hull[i], hull[(i + 1) % m]);

    return perim;
}
