/*
 * Compute the rank (i.e., index in the sorted order) for each element of x.
 *
 * The implementation uses a vector of pair<value,index> as the key for sorting.
 * This removes the need for a second iota pass and keeps the algorithm
 * O(n log n) while staying fully deterministic and thread‑safe.
 *
 * The function signature is kept identical to the original for the harness.
 */
inline void ranks(std::vector<float> const& x, std::vector<size_t>& ranks_) {
    const std::size_t n = x.size();
    if (ranks_.size() < n) ranks_.resize(n);

    // Build pairs (value, original_index) directly to avoid a separate indices array.
    std::vector<std::pair<float, std::size_t>> pairs;
    pairs.reserve(n);
    for (std::size_t i = 0; i < n; ++i) {
        pairs.emplace_back(x[i], i);
    }

    // Sort by value; stable ordering keeps deterministic result for equal values.
    std::stable_sort(pairs.begin(), pairs.end(),
                     [](const std::pair<float, std::size_t>& a,
                        const std::pair<float, std::size_t>& b) {
                         return a.first < b.first;
                     });

    // Fill the output ranks array.
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[pairs[i].second] = i;
    }
}

