        std::size_t localIdx = 0;
        double localDiff = std::numeric_limits<double>::infinity();

        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i) {
            const double d = std::abs(x[i] - PI);
            if (d < localDiff) {
                localDiff = d;
                localIdx  = i;
            }
        }

        #pragma omp critical
        {
            if (localDiff < bestDiff) {
                bestDiff = localDiff;
                bestIdx  = localIdx;
            }
        }
    }

    return bestIdx;
}
