#pragma once
#include <vector>
#include <unordered_set>
#include <algorithm>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither. */
inline bool xorContains(std::vector<int> const& x,
                        std::vector<int> const& y,
                        int val) noexcept
{
    // If one vector is empty, the result is just whether the value
    // exists in the other vector.
    if (x.empty() && y.empty()) return false;
    if (x.empty()) return std::find(y.begin(), y.end(), val) != y.end();
    if (y.empty()) return std::find(x.begin(), x.end(), val) != x.end();

    // Build a hash set from the smaller vector for O(1) look‑ups.
    const std::vector<int> *small = &x, *large = &y;
    if (x.size() > y.size()) std::swap(small, large);

    std::unordered_set<int> hash;
    hash.reserve(small->size());
    for (int v : *small) hash.insert(v);

    const bool foundInLarge = std::find(large->begin(), large->end(), val) != large->end();
    const bool foundInSmall = hash.find(val) != hash.end();

    return foundInLarge ^ foundInSmall;
}
