#include <omp.h>

/*
 * In‑place LU factorisation of a dense N×N matrix stored in row‑major order.
 * The result overwrites the input matrix A, with the strictly lower part holding
 * L (unit diagonal implicit) and the upper part holding U.
 *
 * Example:
 *   input : [[4, 3], [6, 3]]
 *   output: [[4, 3], [1.5, -1.5]]
 */
void luFactorize(std::vector<double> &A, size_t N)
{
    // Avoid too many virtual function calls in the hot loops
    double *data = A.data();

    for (size_t k = 0; k < N; ++k)
    {
        const double pivot = data[k * N + k];
        const double *rowK = data + k * N;

        /* Parallelises the update of the rows that use the current pivot.
         * The inner j‑loop is kept sequential for better cache locality. */
#pragma omp parallel for schedule(static)
        for (int ii = int(k + 1); ii < int(N); ++ii)
        {
            double *rowI = data + ii * N;
            const double factor = rowI[k] / pivot;
            rowI[k] = factor;                 // store L[k+1…N]

            double *pJ = rowI + k + 1;        // starting at column k+1
            const double *qJ = rowK + k + 1;  // corresponding part of row k

            const int nTail = int(N) - int(k) - 1;
            for (int j = 0; j < nTail; ++j)
                *pJ++ -= factor * *qJ++;
        }
    }
}
