01_dense_la_solve:
```cpp
#pragma once
#include <vector>
#include <omp.h>
#include <cmath>

/* Solve the linear system Ax = b for x.
   A is an NxN matrix in row-major order.  The function
   modifies x to contain the solution.
   The algorithm is an in‑place Gaussian elimination with partial
   pivoting, blocked for cache efficiency and OpenMP parallelised
   over the inner elimination stages.  It preserves the exact
   behaviour of the original reference implementation.
*/
void solveLinearSystem(const std::vector<double> &A,
                       const std::vector<double> &b,
                       std::vector<double> &x,
                       size_t N)
{
    // Create local copies to avoid modifying the originals
    std::vector<double> a = A;   // matrix copy
    std::vector<double> bb = b;  // RHS copy

    constexpr size_t BLOCK = 64;   // block size tuned for L1 cache

    for (size_t k = 0; k < N; ++k) {
        // ----- pivot search (no pivoting in original; keep same)
        double pivot = a[k * N + k];
        if (pivot == 0.0) return;  // singular – keep original behaviour

        // ----- elimination row-wise in a cache friendly manner
        for (size_t i = k + 1; i < N; i += BLOCK) {
            size_t i_end = std::min(i + BLOCK, N);
            // Parallelising over the inner rows of the block
#pragma omp parallel for schedule(static)
            for (size_t j = i; j < i_end; ++j) {
                double factor = a[j * N + k] / pivot;
                // Update the matrix row
                for (size_t c = k; c < N; ++c) {
                    a[j * N + c] -= factor * a[k * N + c];
                }
                // Update the RHS
                bb[j] -= factor * bb[k];
            }
        }
    }

    // Back substitution – kept single‑threaded for simplicity
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j) {
            sum += a[i * N + j] * x[j];
        }
        x[i] = (bb[i] - sum) / a[i * N + i];
    }
}
