#include <omp.h>

/*
 * Multiply the matrix A by the vector x. Store the results in the vector y.
 * A is an MxN matrix stored in row‑major, x has N elements, and y has M elements.
 *
 * Example:
 *   input:  A=[[1, -1, 2], [0, -3, 1]]  x=[2, 1, 0]
 *   output: y=[1, -3]
 *
 * This implementation is heavily optimised for a modern x86‑64 machine with
 * 8 hardware threads.  It uses OpenMP to parallelise over the outer
 * dimension, processes the rows in tiles to improve cache locality, and
 * performs the inner product with a hand‑rolled loop that removes a few
 * redundant operations.  All behaviour is identical to a standard
 * matrix‑vector product.
 */

inline void gemv(
    std::vector<double> const& A,
    std::vector<double> const& x,
    std::vector<double>       & y,
    std::size_t                M,
    std::size_t                N)
{
    // Ensure the destination vector has the right size
    if (y.size() != M) y.resize(M);

    // Raw pointers for maximum speed
    const double * restrict Ap = A.data();
    const double * restrict xp = x.data();
          double * restrict yp = y.data();

    // Tile size: number of rows processed per OpenMP chunk.
    // 256 rows gives a good balance between parallel work and cache usage
    const std::size_t tile = 256;

    #pragma omp parallel for schedule(static, tile) collapse(1)
    for (std::size_t i = 0; i < M; ++i) {
        // initialise this row
        double sum = 0.0;

        // Pointer to the start of the current row
        const double *a = Ap + i * N;

        // Unroll the inner loop by 4 to reduce loop overhead
        std::size_t j = 0;
        std::size_t j_end = N & ~3ULL;          // floor to multiple of 4
        for (; j < j_end; j += 4) {
            sum += a[j    ] * xp[j    ]
                 + a[j + 1] * xp[j + 1]
                 + a[j + 2] * xp[j + 2]
                 + a[j + 3] * xp[j + 3];
        }
        // Tail handling
        for (; j < N; ++j) {
            sum += a[j] * xp[j];
        }

        yp[i] = sum;
    }
}
