#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
//  Iterative radix‑2 Cooley–Tukey FFT (forward)
//  -----------------------------------------------------------------------------
static void fft_forward(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // Bit‑reversal permutation
    std::size_t log2N = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = i;
        j = ((j & 0x55555555u) << 1) | ((j & 0xAAAAAAAAu) >> 1);
        j = ((j & 0x33333333u) << 2) | ((j & 0xCCCCCCCCu) >> 2);
        j = ((j & 0x0F0F0F0Fu) << 4) | ((j & 0xF0F0F0F0u) >> 4);
        j = ((j & 0x00FF00FFu) << 8) | ((j & 0xFF00FF00u) >> 8);
        j = (j >> 16) | (j << 16);
        j >>= (32 - log2N);
        if (j > i) std::swap(x[i], x[j]);
    }

    // Pre‑compute twiddle factors for each stage
    std::vector<std::complex<double>> roots(N / 2);
    double ang = -2 * M_PI / static_cast<double>(N);
    for (std::size_t i = 0; i < N / 2; ++i)
        roots[i] = std::exp(std::complex<double>(0.0, ang * static_cast<double>(i)));

    // Main FFT loops
    for (std::size_t len = 2; len <= N; len <<= 1)
    {
        std::size_t half = len >> 1;
        std::size_t step = N / len;

        // Parallelise over butterfly groups
#pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                std::size_t k = j * step;
                std::complex<double> t  = roots[k] * x[i + j + half];
                std::complex<double> u  = x[i + j];
                x[i + j]        = u + t;
                x[i + j + half] = u - t;
            }
        }
    }
}

// -----------------------------------------------------------------------------
//  Inverse FFT using the forward FFT routine (conjugate‑transform trick)
//  -----------------------------------------------------------------------------
void ifft(std::vector<std::complex<double>> &x)
{
    // 1. Conjugate and forward FFT
