    const std::size_t n = x.size();

    // ---- 1️⃣ Count non‑zero elements ------------------------------------
    std::size_t nz_count = 0;
    #pragma omp parallel for reduction(+ : nz_count) schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        if (x[i] != 0) ++nz_count;
    }

    // If there are no non‑zeros, nothing to do.
    if (nz_count == 0) return;

    // ---- 2️⃣ Extract non‑zero elements ----------------------------------
    std::vector<int> nz;
    nz.resize(nz_count);

    std::size_t idx = 0;
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
