            // Atomic increment to obtain unique index
            std::size_t pos = __sync_fetch_and_add(&idx, 1);
            nz[pos] = x[i];
        }
    }

    // ---- 3️⃣ Sort the collected elements ---------------------------------
    std::sort(nz.begin(), nz.end());

    // ---- 4️⃣ Write sorted values back to the original vector -------------
    std::size_t write_idx = 0;
    for (std::size_t i = 0; i < n; ++i) {
        if (x[i] != 0) {
            x[i] = nz[write_idx++];
        }
    }
