struct Point {
    double x, y;
};
using PointVec = std::vector<Point>;

/* Helper: Euclidean distance between two points */
static inline double dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Recursive divide‑and‑conquer helper.  A sorted-by-x vector `pts` and a
   temporary buffer `tmp` (same size) are passed.  The return value is
   the minimum distance in the sub‑range [l, r). */
static double closestRec(PointVec& pts, PointVec& tmp,
                         size_t l, size_t r, bool sortByY) {
    const size_t n = r - l;
    if (n <= 3) {                            // brute force
        double d = std::numeric_limits<double>::infinity();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                d = std::min(d, dist(pts[i], pts[j]));
        if (sortByY) {
            std::sort(pts.begin() + l, pts.begin() + r,
                      [](const Point& a, const Point& b) { return a.y < b.y; });
        }
        return d;
    }

    size_t mid = l + n / 2;
    double midx = pts[mid].x;

    double dLeft  = closestRec(pts, tmp, l, mid, true);
    double dRight = closestRec(pts, tmp, mid, r, true);
    double d = std::min(dLeft, dRight);

    /* Merge the two halves sorted by y into tmp */
    size_t i = l, j = mid, k = l;
    while (i < mid && j < r) {
        if (pts[i].y < pts[j].y) tmp[k++] = pts[i++];
        else                    tmp[k++] = pts[j++];
    }
    while (i < mid) tmp[k++] = pts[i++];
    while (j < r)  tmp[k++] = pts[j++];
    for (size_t idx = l; idx < r; ++idx) pts[idx] = tmp[idx];

    /* Build strip of points within d of mid line */
    std::vector<Point> strip;
    strip.reserve(n);
    for (size_t idx = l; idx < r; ++idx) {
        if (std::abs(pts[idx].x - midx) < d)
            strip.push_back(pts[idx]);
    }

    /* Check strip - at most 7 neighbours per point (theoretical bound) */
    for (size_t p = 0; p < strip.size(); ++p) {
        for (size_t q = p + 1;
             q < strip.size() && (strip[q].y - strip[p].y) < d; ++q) {
            d = std::min(d, dist(strip[p], strip[q]));
        }
    }
    return d;
}

/* Public API: finds minimum distance between any two points */
double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    /* Make a working copy sorted by x */
    PointVec pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) { return a.x < b.x; });

    /* Temporary buffer for merges */
    PointVec tmp(n);

    /* The recursive routine sorts each half by y after returning, so the
       initial call does not need to sort by y. */
    double minDist = closestRec(pts, tmp, 0, n, false);
    return minDist;
}
