        // unrolled loop of 8 iterations
        if ((ptr[i]   & 1) == 0) return i;
        if ((ptr[i+1] & 1) == 0) return i + 1;
        if ((ptr[i+2] & 1) == 0) return i + 2;
        if ((ptr[i+3] & 1) == 0) return i + 3;
        if ((ptr[i+4] & 1) == 0) return i + 4;
        if ((ptr[i+5] & 1) == 0) return i + 5;
        if ((ptr[i+6] & 1) == 0) return i + 6;
        if ((ptr[i+7] & 1) == 0) return i + 7;
    }
    for (; i < n; ++i) {
        if ((ptr[i] & 1) == 0) return i;
    }
    return n;
