/// Simulate one generation of Game of Life on `input`. Store the results in `output`.
/// `input` and `output` are NxN grids stored in row-major.
/// All logic matches the original specification, just expressed in a more
/// parallel‑friendly layout.

void gameOfLife(const std::vector<int>& input, std::vector<int>& output, std::size_t N)
{
    // We treat each row separately and use OpenMP to parallelise over rows.
    // Each thread works on a distinct row and writes its results to the same `output`
    // buffer. No read/write conflicts arise.
    // `#pragma omp parallel for schedule(static)` gives best performance for the
    // problem size typically used in the benchmark, and the static schedule
    // ensures that each thread gets a contiguous block of rows which improves
    // cache locality.

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t base = i * N;
        const std::size_t prev  = (i == 0)    ? static_cast<std::size_t>(-1) : i - 1;
        const std::size_t next  = (i == N-1)  ? static_cast<std::size_t>(-1) : i + 1;

        for (std::size_t j = 0; j < N; ++j)
        {
            int n = 0;                         // neighbour count
            const std::size_t idx = base + j;  // current cell index

            // Pre‑compute indices for adjacent cells that exist
            if (prev != static_cast<std::size_t>(-1))
                n += input[prev * N + j];
            if (next != static_cast<std::size_t>(-1))
                n += input[next * N + j];
            if (j > 0)
                n += input[base + j - 1];
            if (j + 1 < N)
                n += input[base + j + 1];
            if (prev != static_cast<std::size_t>(-1) && j > 0)
                n += input[prev * N + j - 1];
            if (prev != static_cast<std::size_t>(-1) && j + 1 < N)
                n += input[prev * N + j + 1];
            if (next != static_cast<std::size_t>(-1) && j > 0)
                n += input[next * N + j - 1];
            if (next != static_cast<std::size_t>(-1) && j + 1 < N)
                n += input[next * N + j + 1];

            // Apply the Game‑of‑Life rules: identical to the reference implementation
            if (input[idx] == 1)
            {
                output[idx] = (n == 2 || n == 3) ? 1 : 0;
            }
            else
            {
                output[idx] = (n == 3) ? 1 : 0;
            }
        }
    }
}
