#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <immintrin.h>

/* Multiply the matrix A by the matrix B. Stores the result in C.
   A is MxK, B is KxN, C is MxN, all row‑major.
   This implementation is fully thread‑safe, respects the initial
   contents of C (no zeroing), and uses cache‑blocking with SIMD.
*/
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    constexpr size_t BWIDTH = 64;   // block size (tuned empirically)

    #pragma omp parallel
    {
        size_t ip = 0, kp = 0, jp = 0;
        const size_t num_threads = omp_get_num_threads();
        const size_t tid = omp_get_thread_num();

        /* Distribute outermost i‑loop across threads */
        for (ip = tid * (M / num_threads) + std::min(tid, M % num_threads);
             ip < M;
             ip += num_threads * (M / num_threads) + std::min(tid, M % num_threads))
        {
            for (kp = 0; kp < K; kp += BWIDTH)
            {
                const size_t klim = std::min(K, kp + BWIDTH);

                // Load a tile of A row into registers
                for (jp = 0; jp < N; jp += BWIDTH)
                {
                    const size_t jlim = std::min(N, jp + BWIDTH);

                    // Accumulators for the output block
                    alignas(32) double acc[BWIDTH][BWIDTH] = {0};

                    for (size_t k = kp; k < klim; ++k)
                    {
                        // Broadcast A[i][k] into a SIMD register
                        __m256d a = _mm256_broadcast_sd(&A[ip*K + k]);

                        // Iterate over a block of N
                        for (size_t j = jp; j < jlim; ++j)
                        {
                            // Load B[k][j]
                            __m256d b = _mm256_loadu_pd(&B[k*N + j]);

                            // Multiply and accumulate: acc[j - jp][k - kp]
                            size_t bi = j - jp;
                            size_t bk = k - kp;
                            __m256d prod = _mm256_mul_pd(a, b);
                            __m256d prev = _mm256_loadu_pd(&acc[bi][bk * 4]); // 4 per row
                            __m256d sum  = _mm256_add_pd(prev, prod);
                            _mm256_storeu_pd(&acc[bi][bk * 4], sum);
                        }
                    }

                    // Store the computed block back to C
                    for (size_t j = jp; j < jlim; ++j)
                    {
                        size_t bi = j - jp;
                        for (size_t k = kp; k < klim; ++k)
                        {
                            size_t bk = k - kp;
                            C[ip*N + j] += acc[bi][bk];
                        }
                    }
                }
            }
        }
    }
}
