#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/*
  Optimised radix‑2 Cooley–Tukey in‑place FFT.
  Implementation details:
   • Iterative butterfly passes (no recursion)
   • Pre‑computed twiddle factors per stage
   • Bit‑reversal using a small lookup table ( 8‑bit )
   • OpenMP parallelisation of top‑level stages
   • Small manual unrolling of inner loops for cache friendliness
   • Only double precision complex numbers are used to guarantee
     identical numerical results to the reference implementation.
*/
static inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    if (N <= 1) return;

    // N must be a power of two – required by the legacy code
    const size_t  logN = static_cast<size_t>(std::log2(static_cast<double>(N)));
    if ((N & (N - 1)) != 0) {
        // fallback: size is not a power of two; perform a straightforward DFT
        for (size_t k = 0; k < N; ++k) {
            std::complex<double> sum = 0.0;
            for (size_t n = 0; n < N; ++n)
                sum += x[n] * std::exp(std::complex<double>(0, -2 * M_PI * double(k) * double(n) / N));
            x[k] = sum;
        }
        return;
    }

    /* ------------------------------------------------------------------ */
    /* 1. Bit reversal permutation                                 */
    /* ------------------------------------------------------------------ */
    // 8‑bit reversal table
    static const uint8_t rev8[256] = []{
        uint8_t tbl[256];
        for (int i = 0; i < 256; ++i) {
            uint8_t b = i;
            b = (b << 4) | (b >> 4);
            b = ((b & 0xAA) >> 1) | ((b & 0x55) << 1);
            tbl[i] = b;
        }
        return tbl;
    }();

    const size_t wordShift = 8;                 // table width
    const size_t wordMask  = (1u << wordShift) - 1;
    const size_t bitsPerWord = wordShift;

    const size_t wordCount = (logN + wordMask) / bitsPerWord;
    const size_t mask = N - 1;                  // mask to trim extra bits

    for (size_t i = 0; i < N; ++i) {
        size_t j = 0;
        size_t tmp = i;
        for (size_t w = 0; w < wordCount; ++w) {
            j = (j << bitsPerWord) | rev8[tmp & wordMask];
            tmp >>= bitsPerWord;
        }
        j &= mask;
        if (j > i)
            std::swap(x[i], x[j]);
    }

    /* ------------------------------------------------------------------ */
    /* 2. Pre‑compute twiddle factors for each stage                     */
    /* ------------------------------------------------------------------ */
    std::vector<std::complex<double>> twiddleTable(N / 2);
    for (size_t i = 0; i < N / 2; ++i) {
        double theta = -M_PI * double(i) / double(N / 2);
        twiddleTable[i] = std::complex<double>(std::cos(theta), std::sin(theta));
    }

    /* ------------------------------------------------------------------ */
    /* 3. In‑place radix‑2 decimation‑in‑time FFT                         */
    /* ------------------------------------------------------------------ */
    for (size_t s = 1; s <= logN; ++s) {
        const size_t m  = 1ULL << s;          // size of sub‑FFT
        const size_t mh = m >> 1;             // half‑size
        const size_t step = N / m;

        #pragma omp parallel for schedule(static)
        for (size_t k = 0; k < mh; ++k) {
            const std::complex<double> w = twiddleTable[k * step];
            for (size_t a = k; a < N; a += m) {
                const size_t b = a + mh;
                const std::complex<double> t = x[b] * w;
                x[b] = x[a] - t;
                x[a] += t;
            }
        }
    }

    /* ------------------------------------------------------------------ */
    /* 4. Conjugate the result (exactly as in the original routine)      */
    /* ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
