struct Result {
    int startTime;
    int duration;
    float value;
};

/* Sort vector of Result structs by start time in ascending order.
   Uses a parallel quick‑sort with OpenMP tasks for maximum speed.
   The algorithm falls back to std::sort for very small sub‑ranges
   or when recursion depth is too high. */
static inline bool cmpStartTime(const Result& a, const Result& b) {
    return a.startTime < b.startTime;
}

/* Cut‑off for serial sorting: sub‑ranges smaller than this are sorted
   with std::sort to avoid excessive task overhead. */
constexpr std::size_t SERIAL_THRESH = 1 << 12;     // 4 096 elements
constexpr int MAX_DEPTH = 16;                     // limit recursion depth

static inline void parallel_quicksort(Result* first, Result* last, int depth = 0) {
    std::size_t n = last - first;
    if (n <= 1) return;                                   // already sorted
    if (n < SERIAL_THRESH || depth >= MAX_DEPTH) {        // small or deep enough
        std::sort(first, last, cmpStartTime);
        return;
    }

    // choose pivot as element in the middle
    Result* pivot = first + n / 2;
    Result pivotVal = *pivot;

    // partition around pivot
    std::size_t left = 0, right = n - 1;
    while (left <= right) {
        while (cmpStartTime(*(first + left), pivotVal)) ++left;
        while (cmpStartTime(pivotVal, *(first + right))) --right;
        if (left <= right) {
            std::swap(*(first + left), *(first + right));
            ++left; --right;
        }
    }

    // recursively sort left and right halves in parallel tasks
#pragma omp task firstprivate(first, last, depth)
    {
        parallel_quicksort(first, first + right + 1, depth + 1);
    }
#pragma omp task firstprivate(first, last, depth)
    {
        parallel_quicksort(first + left, last, depth + 1);
    }
}

/* Public API – preserves original function signature. */
inline void sortByStartTime(std::vector<Result> &results) {
    if (results.size() <= 1) return;
#pragma omp parallel
    {
#pragma omp single
        {
            parallel_quicksort(results.data(), results.data() + results.size());
        }
    }
}
