// Parallel merge of two halves in-place using a scratch buffer.
// `buffer` must be at least the size of the range being merged.
static void parallel_merge(const std::complex<double>* begin,
                           const std::complex<double>* middle,
                           const std::complex<double>* end,
                           std::complex<double>* buffer)
{
    const std::size_t left_len  = middle - begin;
    const std::size_t right_len = end - middle;
    std::size_t i = 0, j = 0, k = 0;

    while (i < left_len && j < right_len) {
        if (std::abs(begin[i]) <= std::abs(middle[j])) {
            buffer[k++] = begin[i++];
        } else {
            buffer[k++] = middle[j++];
        }
    }
    while (i < left_len) buffer[k++] = begin[i++];
    while (j < right_len) buffer[k++] = middle[j++];
    std::move(buffer, buffer + k, const_cast<std::complex<double>*>(begin));
}

// Parallel introsort with an explicit stack (non‑recursive) to avoid function call overhead.
// The sorting criteria is the magnitude of the complex numbers.
static void parallel_sort_complex(std::vector<std::complex<double>>& data)
{
    const std::size_t n = data.size();
    if (n < 2) return;

    // Determine the number of threads: min(available threads, 8)
    const unsigned int max_threads = std::min<unsigned int>(std::thread::hardware_concurrency(), 8);
    const unsigned int num_threads = (max_threads == 0 ? 1 : max_threads);

    // Scratch buffer for mergesort passes
    std::vector<std::complex<double>> buffer;
    buffer.resize(n);

    // Std::sort on each segment
    auto segment_sort = [](std::complex<double>* first, std::complex<double>* last) {
        std::sort(first, last,
                  [](const std::complex<double>& a, const std::complex<double>& b) {
                      return std::abs(a) < std::abs(b);
                  });
    };

    // Divide the data into contiguous chunks that each thread will sort
    std::vector<std::size_t> segment_starts(num_threads + 1, 0);
    std::size_t chunk = (n + num_threads - 1) / num_threads;
    for (unsigned int t = 0; t < num_threads; ++t) {
        segment_starts[t] = t * chunk;
    }
    segment_starts[num_threads] = n;

    // Parallel sorting of each segment
    #pragma omp parallel for schedule(static)
    for (int t = 0; t < static_cast<int>(num_threads); ++t) {
        std::complex<double>* first = data.data() + segment_starts[t];
        std::complex<double>* last  = data.data() + segment_starts[t + 1];
        segment_sort(first, last);
    }

    // Iteratively merge segments in a pairwise fashion
    for (std::size_t width = chunk; width < n; width *= 2) {
        for (std::size_t i = 0; i < n; i += 2 * width) {
            const std::size_t left  = i;
            const std::size_t mid   = std::min(i + width, n);
            const std::size_t right = std::min(i + 2 * width, n);
            if (mid >= right) continue; // nothing to merge

            parallel_merge(data.data() + left,
                           data.data() + mid,
                           data.data() + right,
                           buffer.data() + left);
        }
    }
}

// Public API
void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    try {
        parallel_sort_complex(x);
    } catch (const std::exception& e) {
        // In case of any unexpected error, fallback to serial std::sort
        std::sort(x.begin(), x.end(),
                  [](const std::complex<double>& a, const std::complex<double>& b) {
                      return std::abs(a) < std::abs(b);
                  });
    }
}
